const items = $input.all();
const mappedItems = items.map(item => {
  const candidate = item.json;

  const candidateId = candidate.id_1 || candidate.id;
  const candidateName = candidate.name_1 || candidate.name;
  const candidateSkills = candidate.skills_1 || candidate.skills;
  const candidateExperience = candidate.experience_1 || candidate.experience;

  const jobId = candidate.id_2 || candidate.id;
  const jobTitle = candidate.job_title_2 || candidate.job_title || candidate.title_2;
  const jobCompany = candidate.company_2 || candidate.company;
  const jobDesc = candidate.job_description_2 || candidate.job_description || candidate.description_2;

  const promptText = `SYSTEM:\nYou are an expert recruitment screening assistant. Evaluate the fit between the candidate and the job opening. You must respond with a raw JSON object and nothing else.\n\nCANDIDATE PROFILE:\n- Name: ${candidateName}\n- Target Skills: ${candidateSkills}\n- Experience Summary: ${candidateExperience}\n\nJOB OPENING DETAILS:\n- Title: ${jobTitle}\n- Company: ${jobCompany}\n- Description/Requirements: ${jobDesc}\n\nJSON OUTPUT SCHEMA REQUIREMENT:\nYou must return a valid JSON object matching this exact key structure:\n{\n  "overall_score": (0-100 integer representing match quality),\n  "decision": (exactly "Proceed", "Hold", or "Reject"),\n  "strengths": ["strength 1", "strength 2"],\n  "missing_skills": ["missing skill 1", "missing skill 2"],\n  "reasoning": "1-2 sentences justifying the decision and score",\n  "summary": "Brief executive summary of candidate fit"\n}\n\nStrict Constraint: Output raw JSON only. Do not add conversational intro/outro text.`;

  return {
    json: {
      ollama_prompt: {
        model: "qwen2.5:7b",
        messages: [
          {
            role: "system",
            content: "You are a precise, objective screening assistant that outputs strict JSON matching the requested structure."
          },
          {
            role: "user",
            content: promptText
          }
        ],
        temperature: 0.15
      },
      candidate_database_id: candidateId,
      job_database_id: jobId
    }
  };
});

return mappedItems;

const items = $input.all();

const parsedResults = items.map((item) => {
  try {
    // 1. Extract the raw content
    const rawContent = item.json?.message?.content || item.json?.choices?.[0]?.message?.content || "";

    if (!rawContent) {
       throw new Error("No content found in Ollama response.");
    }

    // 2. Extract JSON using a safer regex that ignores surrounding text
    // Matches everything between the first '{' and the last '}'
    const jsonStr = rawContent.substring(rawContent.indexOf("{"), rawContent.lastIndexOf("}") + 1);

    if (!jsonStr) {
      throw new Error("No JSON structure detected in response.");
    }

    const evaluationData = JSON.parse(jsonStr);

    return {
      json: {
        overall_score: Number(evaluationData.overall_score || 0),
        decision: evaluationData.decision || "Hold",
        strengths: Array.isArray(evaluationData.strengths) ? evaluationData.strengths : [],
        missing_skills: Array.isArray(evaluationData.missing_skills) ? evaluationData.missing_skills : [],
        reasoning: evaluationData.reasoning || "No reasoning provided.",
        summary: evaluationData.summary || "No summary provided.",
        parse_success: true
      }
    };
  } catch (err) {
    // Return a structured failure object so the workflow can continue
    return {
      json: {
        overall_score: 0,
        decision: "Hold",
        strengths: [],
        missing_skills: [],
        reasoning: `Parsing Error: ${err.message}`,
        summary: "Failed to parse LLM response.",
        parse_success: false
      }
    };
  }
});

return parsedResults;
